import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";

export default function Navbar() {
  const { user, isAuthenticated, logout } = useAuth();
  const { pushToast } = useToast();
  const navigate = useNavigate();

  const onLogout = async () => {
    try {
      await logout();
      pushToast("Logged out", "info");
      navigate("/login", { replace: true });
    } catch (err) {
      pushToast(err.message || "Logout failed", "error");
    }
  };

  return (
    <header className="navbar">
      <div className="nav-content">
        <div className="nav-brand">
          <strong>Seta Auth Portal</strong>
          <span>Stage 1 • Identity and Team Foundation</span>
        </div>

        <nav className="nav-links">
          {!isAuthenticated && (
            <>
              <Link className="nav-link" to="/login">
                Login
              </Link>
              <Link className="nav-link" to="/register">
                Register
              </Link>
            </>
          )}

          {isAuthenticated && (
            <>
              <Link className="nav-link" to="/profile">
                My Profile
              </Link>
              {user?.role === "manager" && (
                <Link className="nav-link" to="/users">
                  Users
                </Link>
              )}
              <button type="button" className="nav-btn" onClick={onLogout}>
                Logout
              </button>
            </>
          )}
        </nav>
      </div>
    </header>
  );
}

import { NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";

export default function Navbar() {
  const { user, isAuthenticated, logout } = useAuth();
  const { pushToast } = useToast();
  const navigate = useNavigate();

  const onLogout = async () => {
    try {
      await logout();
      pushToast("Logged out", "info");
      navigate("/login", { replace: true });
    } catch (err) {
      pushToast(err.message || "Logout failed", "error");
    }
  };

  const navClassName = ({ isActive }) => (isActive ? "nav-link nav-link-active" : "nav-link");

  return (
    <header className="navbar">
      <div className="nav-content">
        <div className="nav-brand">
          <strong>Seta Auth Portal</strong>
          <span>Stage 1 • Identity and Team Foundation</span>
        </div>

        <nav className="nav-links">
          {!isAuthenticated && (
            <>
              <NavLink className={navClassName} to="/login">
                Login
              </NavLink>
              <NavLink className={navClassName} to="/register">
                Register
              </NavLink>
            </>
          )}

          {isAuthenticated && (
            <>
              <NavLink className={navClassName} to="/profile">
                My Profile
              </NavLink>
              {user?.role === "manager" && (
                <NavLink className={navClassName} to="/users">
                  Users
                </NavLink>
              )}
              <button type="button" className="nav-btn" onClick={onLogout}>
                Logout
              </button>
            </>
          )}
        </nav>
      </div>
    </header>
  );
}

import { useAuth } from "../context/AuthContext";

export default function ProfilePage() {
  const { user } = useAuth();

  return (
    <section className="card page-panel profile-panel">
      <h2>My Profile</h2>
      <div className="profile-grid">
        <p className="profile-row">
          <strong>User ID:</strong> {user?.userId}
        </p>
        <p className="profile-row">
          <strong>Username:</strong> {user?.username}
        </p>
        <p className="profile-row">
          <strong>Email:</strong> {user?.email}
        </p>
        <p className="profile-row">
          <strong>Role:</strong> {user?.role}
        </p>
        <p className="profile-row">
          <strong>Verification:</strong> {user?.isVerified ? "Verified" : "Pending verification"}
        </p>
      </div>
    </section>
  );
}

import { useEffect, useState } from "react";
import { listUsersApi } from "../api/userApi";
import { useAuth } from "../context/AuthContext";

export default function UsersPage() {
  const { token } = useAuth();
  const [users, setUsers] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    async function loadUsers() {
      try {
        const data = await listUsersApi(token, 1, 50);
        if (active) {
          setUsers(data.data || []);
        }
      } catch (err) {
        if (active) {
          setError(err.message);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadUsers();
    return () => {
      active = false;
    };
  }, [token]);

  if (loading) {
    return (
      <section className="card page-panel users-panel">
        <h2>Users (Manager only)</h2>
        <div className="state-card">Loading users...</div>
      </section>
    );
  }

  return (
    <section className="card page-panel users-panel">
      <h2>Users (Manager only)</h2>
      {error && <p className="error">{error}</p>}
      {!error && (
        <div className="table-wrap">
          <table className="table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Username</th>
                <th>Email</th>
                <th>Role</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.userId}>
                  <td>{u.userId}</td>
                  <td>{u.username}</td>
                  <td>{u.email}</td>
                  <td>{u.role}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </section>
  );
}

import { useEffect, useState } from "react";
import { listUsersApi } from "../api/userApi";
import { useAuth } from "../context/AuthContext";

export default function UsersPage() {
  const { token } = useAuth();
  const [users, setUsers] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    async function loadUsers() {
      try {
        const data = await listUsersApi(token, 1, 50);
        if (active) {
          setUsers(data.data || []);
        }
      } catch (err) {
        if (active) {
          setError(err.message);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadUsers();
    return () => {
      active = false;
    };
  }, [token]);

  if (loading) {
    return (
      <section className="card page-panel users-panel" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ color: 'var(--text-muted)', fontSize: '1.1rem' }}>
          <div className="spinner"></div> Loading workspace users...
        </div>
      </section>
    );
  }

  return (
    <section className="card page-panel users-panel">
      <div style={{ marginBottom: '2.5rem' }}>
        <h2 style={{ marginBottom: '0.5rem' }}>Users Directory</h2>
        <p className="muted" style={{ margin: 0 }}>Manager override: Viewing all workspace accounts and access levels.</p>
      </div>

      {error && <p className="error">{error}</p>}
      {!error && (
        <div className="table-wrap">
          <table className="table">
            <thead>
              <tr>
                <th>Member ID</th>
                <th>Username</th>
                <th>Contact Email</th>
                <th>Access Level</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.userId}>
                  <td style={{ opacity: 0.6, fontFamily: 'monospace' }}>#{u.userId}</td>
                  <td style={{ fontWeight: '500', color: '#fff' }}>{u.username}</td>
                  <td className="muted">{u.email}</td>
                  <td>
                    <span className={`badge badge-${u.role}`}>
                      {u.role}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </section>
  );
}

package usecase

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"auth-user-management-service/internal/domain"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/pkg/utils"

	"github.com/google/uuid"
	"gorm.io/gorm"
)

var (
	ErrEmailAlreadyUsed   = errors.New("email already in use")
	ErrInvalidCredentials = errors.New("invalid email or password")
	ErrUserNotFound       = errors.New("user not found")
	ErrSessionUnavailable = errors.New("session not found or already revoked")
	ErrJWTSecretMissing   = errors.New("jwt secret is not configured")
	ErrEmailNotVerified   = errors.New("email is not verified")
	ErrInvalidVerifyToken = errors.New("invalid verification token")
	ErrExpiredVerifyToken = errors.New("verification token expired")
	ErrSMTPNotConfigured  = errors.New("smtp is not fully configured")
)

// RegisterRequest defines the input payload for user registration.
type RegisterRequest struct {
	Username string `json:"username" binding:"required"`
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required,min=8"`
	Role     string `json:"role" binding:"omitempty,oneof=manager member"`
}

// LoginRequest defines the input payload for user login.
type LoginRequest struct {
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required"`
}

// ResendVerificationRequest defines payload to resend verification emails.
type ResendVerificationRequest struct {
	Email string `json:"email" binding:"required,email"`
}

// UserResponse is a safe user payload without password.
type UserResponse struct {
	ID         uint      `json:"userId"`
	Username   string    `json:"username"`
	Email      string    `json:"email"`
	Role       string    `json:"role"`
	IsVerified bool      `json:"isVerified"`
	CreatedAt  time.Time `json:"createdAt"`
	UpdatedAt  time.Time `json:"updatedAt"`
}

// LoginResponse defines login output payload.
type LoginResponse struct {
	AccessToken string       `json:"accessToken"`
	ExpiresAt   time.Time    `json:"expiresAt"`
	User        UserResponse `json:"user"`
}

// AuthUsecase defines the business logic interface.
type AuthUsecase interface {
	Register(req *RegisterRequest) (*domain.User, error)
	VerifyEmail(rawToken string) error
	ResendVerification(req *ResendVerificationRequest) error
	Login(req *LoginRequest) (*LoginResponse, error)
	Logout(tokenID string) error
	ListUsers(page int, limit int) ([]UserResponse, error)
	GetMyProfile(userID uint) (*UserResponse, error)
}

type authUsecaseImpl struct {
	userRepo       repository.UserRepository
	sessionRepo    repository.SessionRepository
	verifyRepo     repository.EmailVerificationRepository
	jwtSecret      string
	jwtTokenTTL    time.Duration
	verifyTokenTTL time.Duration
	appBaseURL     string
	smtpConfig     utils.SMTPConfig
}

// NewAuthUsecase creates a new usecase instance (Dependency Injection).
func NewAuthUsecase(
	userRepo repository.UserRepository,
	sessionRepo repository.SessionRepository,
	verifyRepo repository.EmailVerificationRepository,
) AuthUsecase {
	ttl := 24 * time.Hour
	jwtExpiresHours := strings.TrimSpace(os.Getenv("JWT_EXPIRES_HOURS"))
	if jwtExpiresHours != "" {
		if parsed, err := time.ParseDuration(jwtExpiresHours + "h"); err == nil {
			ttl = parsed
		}
	}

	verifyTTLMinutes := readIntEnvWithDefault("EMAIL_VERIFY_TOKEN_TTL_MINUTES", 5)

	appBaseURL := strings.TrimSuffix(strings.TrimSpace(os.Getenv("APP_BASE_URL")), "/")
	if appBaseURL == "" {
		appBaseURL = "http://localhost:8080"
	}

	return &authUsecaseImpl{
		userRepo:       userRepo,
		sessionRepo:    sessionRepo,
		verifyRepo:     verifyRepo,
		jwtSecret:      strings.TrimSpace(os.Getenv("JWT_SECRET")),
		jwtTokenTTL:    ttl,
		verifyTokenTTL: time.Duration(verifyTTLMinutes) * time.Minute,
		appBaseURL:     appBaseURL,
		smtpConfig:     utils.LoadSMTPConfig(),
	}
}

// Register processes user registration and sends a verification link.
func (u *authUsecaseImpl) Register(req *RegisterRequest) (*domain.User, error) {
	existingUser, err := u.userRepo.FindByEmail(req.Email)
	if err == nil && existingUser != nil {
		return nil, ErrEmailAlreadyUsed
	}
	if err != nil && !errors.Is(err, gorm.ErrRecordNotFound) {
		return nil, err
	}

	hashedPassword, err := utils.HashPassword(req.Password)
	if err != nil {
		return nil, err
	}

	role := req.Role
	if role == "" {
		role = "member"
	}

	user := &domain.User{
		Username:   req.Username,
		Email:      req.Email,
		Password:   hashedPassword,
		Role:       role,
		IsVerified: false,
	}

	if err := u.userRepo.CreateUser(newUser); err != nil {
		return nil, err
	}

	if err := u.issueVerification(newUser); err != nil {
		return nil, err
	}

	return newUser, nil
}

func (u *authUsecaseImpl) VerifyEmail(rawToken string) error {
	tokenHash := hashToken(rawToken)
	verificationToken, err := u.verifyRepo.FindByTokenHash(tokenHash)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return ErrInvalidVerifyToken
		}
		return err
	}

	if verificationToken.UsedAt != nil {
		return ErrInvalidVerifyToken
	}

	if time.Now().After(verificationToken.ExpiresAt) {
		return ErrExpiredVerifyToken
	}

	if err := u.userRepo.MarkUserVerified(verificationToken.UserID); err != nil {
		return err
	}
	if err := u.verifyRepo.MarkUsed(verificationToken.ID); err != nil {
		return err
	}

	return nil
}

func (u *authUsecaseImpl) ResendVerification(req *ResendVerificationRequest) error {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil
		}
		return err
	}

	if user.IsVerified {
		return nil
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	return u.issueVerification(user)
}

func (u *authUsecaseImpl) Login(req *LoginRequest) (*LoginResponse, error) {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrInvalidCredentials
		}
		return nil, err
	}

	if !utils.CheckPasswordHash(req.Password, user.Password) {
		return nil, ErrInvalidCredentials
	}

	if !user.IsVerified {
		return nil, ErrEmailNotVerified
	}

	if u.jwtSecret == "" {
		return nil, ErrJWTSecretMissing
	}

	tokenID := uuid.NewString()
	token, expiresAt, err := utils.GenerateToken(user.ID, user.Role, tokenID, u.jwtSecret, u.jwtTokenTTL)
	if err != nil {
		return nil, err
	}

	err = u.sessionRepo.CreateSession(&domain.Session{
		UserID:    user.ID,
		TokenID:   tokenID,
		ExpiresAt: expiresAt,
	})
	if err != nil {
		return nil, err
	}

	return &LoginResponse{
		AccessToken: token,
		ExpiresAt:   expiresAt,
		User:        toUserResponse(user),
	}, nil
}

func (u *authUsecaseImpl) Logout(tokenID string) error {
	err := u.sessionRepo.RevokeByTokenID(tokenID)
	if err != nil {
		return ErrSessionUnavailable
	}
	return nil
}

func (u *authUsecaseImpl) ListUsers(page int, limit int) ([]UserResponse, error) {
	if page < 1 {
		page = 1
	}
	if limit < 1 || limit > 100 {
		limit = 20
	}

	offset := (page - 1) * limit
	users, err := u.userRepo.ListUsers(offset, limit)
	if err != nil {
		return nil, err
	}

	response := make([]UserResponse, 0, len(users))
	for i := range users {
		response = append(response, toUserResponse(&users[i]))
	}

	return response, nil
}

func (u *authUsecaseImpl) GetMyProfile(userID uint) (*UserResponse, error) {
	user, err := u.userRepo.FindByID(userID)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrUserNotFound
		}
		return nil, err
	}

	response := toUserResponse(user)
	return &response, nil
}

func (u *authUsecaseImpl) issueVerification(user *domain.User) error {
	if !isSMTPConfigured(u.smtpConfig) {
		return ErrSMTPNotConfigured
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	if err := u.verifyRepo.DeleteActiveTokensByUserID(user.ID); err != nil {
		return err
	}

	rawToken := uuid.NewString()
	tokenHash := hashToken(rawToken)
	expiresAt := time.Now().Add(u.verifyTokenTTL)

	verificationToken := &domain.EmailVerificationToken{
		UserID:    user.ID,
		TokenHash: tokenHash,
		ExpiresAt: expiresAt,
	}

	if err := u.verifyRepo.CreateToken(verificationToken); err != nil {
		return err
	}

	verifyURL := fmt.Sprintf("%s/api/v1/auth/verify-email?token=%s", u.appBaseURL, rawToken)
	if err := utils.SendVerificationEmail(u.smtpConfig, user.Email, verifyURL); err != nil {
		return err
	}

	return nil
}

func toUserResponse(user *domain.User) UserResponse {
	return UserResponse{
		ID:         user.ID,
		Username:   user.Username,
		Email:      user.Email,
		Role:       user.Role,
		IsVerified: user.IsVerified,
		CreatedAt:  user.CreatedAt,
		UpdatedAt:  user.UpdatedAt,
	}
}

func hashToken(rawToken string) string {
	sum := sha256.Sum256([]byte(strings.TrimSpace(rawToken)))
	return hex.EncodeToString(sum[:])
}

func readIntEnvWithDefault(key string, fallback int) int {
	value := strings.TrimSpace(os.Getenv(key))
	if value == "" {
		return fallback
	}

	parsed, err := strconv.Atoi(value)
	if err != nil || parsed <= 0 {
		return fallback
	}
	return parsed
}

func isSMTPConfigured(cfg utils.SMTPConfig) bool {
	return cfg.Host != "" && cfg.Username != "" && cfg.Password != ""
}

package usecase

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"auth-user-management-service/internal/domain"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/pkg/utils"

	"github.com/google/uuid"
