package repository

import (
	"time"

	"auth-user-management-service/internal/domain"

	"gorm.io/gorm"
)

// EmailVerificationRepository defines persistence operations for email verification tokens.
type EmailVerificationRepository interface {
	CreateToken(token *domain.EmailVerificationToken) error
	FindByTokenHash(tokenHash string) (*domain.EmailVerificationToken, error)
	MarkUsed(id uint) error
	DeleteActiveTokensByUserID(userID uint) error
	PurgeExpired(now time.Time) error
}

type emailVerificationRepositoryImpl struct {
	db *gorm.DB
}

// NewEmailVerificationRepository creates a new verification repository instance.
func NewEmailVerificationRepository(db *gorm.DB) EmailVerificationRepository {
	return &emailVerificationRepositoryImpl{db: db}
}

func (r *emailVerificationRepositoryImpl) CreateToken(token *domain.EmailVerificationToken) error {
	return r.db.Create(token).Error
}

func (r *emailVerificationRepositoryImpl) FindByTokenHash(tokenHash string) (*domain.EmailVerificationToken, error) {
	var token domain.EmailVerificationToken
	err := r.db.Where("token_hash = ?", tokenHash).First(&token).Error
	if err != nil {
		return nil, err
	}
	return &token, nil
}

func (r *emailVerificationRepositoryImpl) MarkUsed(id uint) error {
	now := time.Now()
	return r.db.Model(&domain.EmailVerificationToken{}).
		Where("id = ? AND used_at IS NULL", id).
		Update("used_at", now).Error
}

func (r *emailVerificationRepositoryImpl) DeleteActiveTokensByUserID(userID uint) error {
	return r.db.Where("user_id = ? AND used_at IS NULL", userID).
		Delete(&domain.EmailVerificationToken{}).Error
}

func (r *emailVerificationRepositoryImpl) PurgeExpired(now time.Time) error {
	return r.db.Where("expires_at < ?", now).
		Delete(&domain.EmailVerificationToken{}).Error
}

@import url('https://fonts.googleapis.com/css2?family=Bricolage+Grotesque:opsz,wght@12..96,400..800&family=Plus+Jakarta+Sans:wght@400;500;600&display=swap');

:root {
  font-family: 'Plus Jakarta Sans', sans-serif;
  --bg-color: #030712;
  --surface-color: rgba(15, 23, 42, 0.45);
  --surface-border: rgba(148, 163, 184, 0.15);
  --surface-hover: rgba(30, 41, 59, 0.6);
  --text-main: #f8fafc;
  --text-muted: #94a3b8;
  --accent: #2dd4bf;
  --accent-glow: rgba(45, 212, 191, 0.35);
  --accent-alt: #38bdf8;
  --danger: #fb7185;
  --radius-card: 28px;
  --radius-pill: 999px;
  --transition: 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background-color: var(--bg-color);
  background-image:
    radial-gradient(circle at 15% 10%, rgba(45, 212, 191, 0.06), transparent 30%),
    radial-gradient(circle at 85% 80%, rgba(56, 189, 248, 0.06), transparent 30%),
    radial-gradient(circle at 50% 50%, rgba(3, 7, 18, 1), #030712 100%);
  background-attachment: fixed;
  color: var(--text-main);
  min-height: 100vh;
}

h1, h2, h3, h4, .nav-brand strong {
  font-family: 'Bricolage Grotesque', sans-serif;
  font-weight: 700;
}

a {
  color: var(--accent);
  text-decoration: none;
  transition: color var(--transition);
}

a:hover {
  color: var(--accent-alt);
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.app-shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  flex: 1;
  max-width: 1240px;
  margin: 0 auto;
  padding: 3rem 1.5rem;
  display: flex;
  flex-direction: column;
  width: 100%;
}

/* NAVBAR - Glassmorphism */
.navbar {
  background: rgba(3, 7, 18, 0.6);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--surface-border);
  padding: 1.2rem 1.5rem;
  position: sticky;
  top: 0;
  z-index: 100;
}

.nav-content {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.nav-brand {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.nav-brand strong {
  font-size: 1.6rem;
  letter-spacing: -0.5px;
  background: linear-gradient(90deg, #fff, #94a3b8);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.nav-brand span {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-family: 'Plus Jakarta Sans', sans-serif;
}

.nav-links {
  display: flex;
  gap: 0.8rem;
  align-items: center;
  flex-wrap: wrap;
}

.nav-link,
.nav-btn {
  color: var(--text-main);
  background: var(--surface-color);
  border: 1px solid var(--surface-border);
  padding: 0.6rem 1.2rem;
  border-radius: var(--radius-pill);
  cursor: pointer;
  font-size: 0.95rem;
  font-weight: 500;
  transition: all var(--transition);
}

.nav-link:hover,
.nav-btn:hover {
  background: var(--surface-hover);
  border-color: rgba(255, 255, 255, 0.3);
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.4);
}

.nav-link-active {
  background: rgba(45, 212, 191, 0.1);
  border-color: var(--accent);
  color: var(--accent);
  box-shadow: 0 0 15px var(--accent-glow);
}

/* CARDS & PANELS */
.card, .auth-hero {
  background: var(--surface-color);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--surface-border);
  border-radius: var(--radius-card);
  padding: 2.5rem;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  animation: fadeUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

.card h2 {
  margin-top: 0;
  margin-bottom: 1rem;
  font-size: 2.2rem;
  letter-spacing: -1px;
  color: #fff;
}

.page-panel {
  max-width: 1080px;
  margin: 0 auto;
}

.profile-panel {
  max-width: 800px;
}

.users-panel {
  min-height: 60vh;
}

/* AUTH LAYOUT */
.auth-layout {
  display: grid;
  grid-template-columns: minmax(360px, 1fr) minmax(460px, 1.2fr);
  gap: 1.5rem;
  max-width: 1100px;
  margin: auto;
  align-items: stretch;
  min-height: clamp(500px, 60vh, 700px);
}

.auth-hero {
  background: linear-gradient(135deg, rgba(15, 23, 42, 0.8) 0%, rgba(3, 7, 18, 0.9) 100%);
  display: flex;
  flex-direction: column;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.auth-hero::after {
  content: '';
  position: absolute;
  top: 0; right: 0; bottom: 0; left: 0;
  background: radial-gradient(circle at top right, var(--accent-glow), transparent 60%);
  pointer-events: none;
}

.auth-hero h2 {
  font-size: 3rem;
  z-index: 1;
}

.auth-hero p {
  color: var(--text-muted);
  font-size: 1.1rem;
  line-height: 1.6;
  z-index: 1;
}

.auth-kicker {
  color: var(--accent);
  text-transform: uppercase;
  font-size: 0.85rem;
  font-weight: 600;
  letter-spacing: 2px;
  margin-bottom: 1rem;
  z-index: 1;
}

/* FORMS */
.form-grid {
  display: grid;
  gap: 1rem;
}

input, select {
  width: 100%;
  padding: 1rem 1.2rem;
  border: 1px solid var(--surface-border);
  border-radius: 14px;
  background: rgba(3, 7, 18, 0.4);
  color: #fff;
  font: inherit;
  transition: var(--transition);
}

input::placeholder {
  color: rgba(148, 163, 184, 0.5);
}

input:focus, select:focus {
  outline: none;
  border-color: var(--accent);
  background: rgba(15, 23, 42, 0.8);
  box-shadow: 0 0 0 4px var(--accent-glow);
}

.input-error {
  border-color: var(--danger);
}

.field-error {
  color: var(--danger);
  font-size: 0.85rem;
  margin: -0.5rem 0 0 0.5rem;
}

button.primary {
  background: var(--text-main);
  color: #030712;
  border: none;
  padding: 1rem;
  border-radius: 14px;
  font-weight: 700;
  font-size: 1rem;
  cursor: pointer;
  transition: var(--transition);
  margin-top: 0.5rem;
  font-family: 'Plus Jakarta Sans', sans-serif;
}

button.primary:hover:not(:disabled) {
  background: var(--accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 25px var(--accent-glow);
}

button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.muted {
  color: var(--text-muted);
}

.page-lead {
  font-size: 1.1rem;
  margin-bottom: 2rem;
}

.error {
  color: var(--danger);
  margin-top: 1rem;
  padding: 1rem;
  background: rgba(251, 113, 133, 0.1);
  border-radius: 12px;
  border: 1px solid rgba(251, 113, 133, 0.2);
}

/* DATA DISPLAYS */
.profile-grid {
  display: grid;
  gap: 0.8rem;
}

.profile-row {
  margin: 0;
  padding: 1.2rem;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--surface-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.profile-row strong {
  color: var(--text-muted);
}

.table-wrap {
  overflow-x: auto;
  border-radius: 20px;
  border: 1px solid var(--surface-border);
  background: rgba(3, 7, 18, 0.3);
}

.table {
  width: 100%;
  border-collapse: collapse;
}

.table th, .table td {
  padding: 1.2rem;
  text-align: left;
  border-bottom: 1px solid var(--surface-border);
}

.table th {
  background: rgba(255, 255, 255, 0.02);
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  font-size: 0.85rem;
  letter-spacing: 1px;
}

.table tr:hover td {
  background: rgba(255, 255, 255, 0.02);
}

.state-card {
  background: rgba(45, 212, 191, 0.1);
  border: 1px solid rgba(45, 212, 191, 0.2);
  color: var(--accent);
  padding: 1.5rem;
  border-radius: 16px;
  text-align: center;
  font-weight: 500;
}

/* TOASTS */
.toast-container {
  position: fixed;
  top: 1.5rem;
  right: 1.5rem;
  display: grid;
  gap: 0.8rem;
  width: min(400px, calc(100vw - 3rem));
  z-index: 1200;
}

.toast {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  border-radius: 16px;
  padding: 1rem 1.2rem;
  color: #fff;
  background: rgba(15, 23, 42, 0.9);
  backdrop-filter: blur(12px);
  border: 1px solid var(--surface-border);
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.6);
  border-left: 4px solid var(--accent-alt);
  animation: fadeUp 0.3s ease-out forwards;
}

.toast-success { border-left-color: var(--accent); }
.toast-error { border-left-color: var(--danger); }

.toast-close {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 1.5rem;
  padding: 0;
  line-height: 1;
}

@media (max-width: 960px) {
  .auth-layout {
    grid-template-columns: 1fr;
  }
  .card, .auth-hero {
    padding: 1.8rem;
  }
}

