import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerApi } from "../api/authApi";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword, validateUsername } from "../utils/validators";

export default function RegisterPage() {
  const navigate = useNavigate();
  const { pushToast } = useToast();
  const [form, setForm] = useState({
    username: "",
    email: "",
    password: "",
  });
  const [touched, setTouched] = useState({
    username: false,
    email: false,
    password: false,
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const usernameError = validateUsername(form.username);
  const emailError = validateEmail(form.email);
  const passwordError = validatePassword(form.password);
  const hasFieldErrors = Boolean(usernameError || emailError || passwordError);

  const onChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ username: true, email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSuccess("");
    setSubmitting(true);

    try {
      await registerApi(form);
      setSuccess("Registration successful. Please verify your email within 5 minutes. Redirecting to login...");
      pushToast("Registration successful. Check your email for the verification link.", "success");
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">Member Onboarding</p>
        <h2>Create Account</h2>
        <p>
          Register as a member account, then verify your email link to activate secure login access.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Register</h2>
        <p className="muted page-lead">Your role is assigned as member at sign-up.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <input
            type="text"
            placeholder="Username"
            value={form.username}
            onChange={(e) => onChange("username", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, username: true }))}
            className={touched.username && usernameError ? "input-error" : ""}
            required
          />
          {touched.username && usernameError && <p className="field-error">{usernameError}</p>}
          <input
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={(e) => onChange("email", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password (min 6 chars)"
            value={form.password}
            onChange={(e) => onChange("password", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            minLength={6}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Creating..." : "Register"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {success && <div className="state-card">{success}</div>}
        <p className="muted auth-switch">
          Already have account? <Link to="/login">Login here</Link>
        </p>
      </section>
    </section>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerApi } from "../api/authApi";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword, validateUsername } from "../utils/validators";

export default function RegisterPage() {
  const navigate = useNavigate();
  const { pushToast } = useToast();
  const [form, setForm] = useState({
    username: "",
    email: "",
    password: "",
    role: "member",
  });
  const [touched, setTouched] = useState({
    username: false,
    email: false,
    password: false,
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const usernameError = validateUsername(form.username);
  const emailError = validateEmail(form.email);
  const passwordError = validatePassword(form.password);
  const hasFieldErrors = Boolean(usernameError || emailError || passwordError);

  const onChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ username: true, email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSuccess("");
    setSubmitting(true);

    try {
      await registerApi(form);
      setSuccess("Registration successful. Please verify your email within 5 minutes. Redirecting to login...");
      pushToast("Registration successful. Check your email for the verification link.", "success");
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">User Onboarding</p>
        <h2>Create Account</h2>
        <p>
          Register your account, then verify your email link to activate secure login access. Choose your capability role below.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Register</h2>
        <p className="muted page-lead">Select your account capability.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <select 
            value={form.role}
            onChange={(e) => onChange("role", e.target.value)}
            className="input-select"
          >
            <option value="member">Member (Read-only Team Access)</option>
            <option value="manager">Manager (Can Create/Manage Teams)</option>
          </select>
          <input
            type="text"
            placeholder="Username"
            value={form.username}
            onChange={(e) => onChange("username", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, username: true }))}
            className={touched.username && usernameError ? "input-error" : ""}
            required
          />
          {touched.username && usernameError && <p className="field-error">{usernameError}</p>}
          <input
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={(e) => onChange("email", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password (min 6 chars)"
            value={form.password}
            onChange={(e) => onChange("password", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            minLength={6}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Creating..." : "Register"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {success && <div className="state-card">{success}</div>}
        <p className="muted auth-switch">
          Already have account? <Link to="/login">Login here</Link>
        </p>
      </section>
    </section>
  );
}

import { useEffect, useState } from "react";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";
import { listMyTeamsApi, createTeamApi, addMemberApi, addManagerApi, removeManagerApi, removeMemberApi, getTeamApi } from "../api/teamApi";
import { listUsersApi, bulkGetUsersApi } from "../api/userApi";

export default function TeamsPage() {
  const { user, token } = useAuth();
  const { pushToast } = useToast();

  const [teams, setTeams] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newTeamName, setNewTeamName] = useState("");
  const [selectedTeam, setSelectedTeam] = useState(null);
  const [users, setUsers] = useState([]);
  const [usersLoading, setUsersLoading] = useState(false);
  const [selectedUserId, setSelectedUserId] = useState("");
  const [userSearchTerm, setUserSearchTerm] = useState("");
  const [userRoleFilter, setUserRoleFilter] = useState("");
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);

  const isManager = user?.role === "manager";

  const fetchTeams = async () => {
    try {
      setLoading(true);
      const res = await listMyTeamsApi(token);
      setTeams(res?.data || []);
    } catch (err) {
      pushToast(err.message || "Failed to load teams", "error");
    } finally {
      setLoading(false);
    }
  };

  const fetchUsers = async () => {
    try {
      setUsersLoading(true);
      const data = await listUsersApi(token, 1, 200);
      setUsers(data?.data || []);
    } catch (err) {
      pushToast(err.message || "Failed to load users", "error");
    } finally {
      setUsersLoading(false);
    }
  };

  const handleCreateTeam = async (e) => {
    e.preventDefault();
    if (!newTeamName.trim()) return;
    try {
      await createTeamApi({ teamName: newTeamName }, token);
      pushToast("Team created", "success");
      setNewTeamName("");
      fetchTeams();
    } catch (err) {
      pushToast(err.message, "error");
    }
  };

  const handleSelectTeam = async (teamId) => {
    try {
      const data = await getTeamApi(teamId, token);
      setSelectedTeam(data);
    } catch (err) {
      pushToast(err.message, "error");
    }
  };

  const handleAction = async (actionFn, ...args) => {
    try {
      await actionFn(...args);
      pushToast("Action successful", "success");
      if (selectedTeam) handleSelectTeam(selectedTeam.teamId);
      setSelectedUserId("");
    } catch (err) {
      pushToast(err.message, "error");
    }
  };

  useEffect(() => {
    if (token) fetchTeams();
  }, [token]);

  useEffect(() => {
    if (token && isManager) fetchUsers();
  }, [token, isManager]);

  useEffect(() => {
    if (!isManager && selectedTeam && token) {
      const ids = [...new Set([...(selectedTeam.managers || []), ...(selectedTeam.members || [])])];
      const missingIds = ids.filter(id => !users.find(u => u.userId === id));
      if (missingIds.length > 0) {
        bulkGetUsersApi(missingIds, token)
          .then(res => {
            if (res?.data) {
              setUsers(prev => {
                const newUsers = res.data.filter(nu => !prev.find(pu => pu.userId === nu.userId));
                return [...prev, ...newUsers];
              });
            }
          })
          .catch(err => {
            console.error("Failed to load team member details", err);
          });
      }
    }
  }, [selectedTeam, isManager, token, users]);

  const userMap = new Map(users.map((u) => [u.userId, u]));
  const formatUserLabel = (id) => {
    const target = userMap.get(id);
    if (!target) return `User #${id}`;
    return `${target.username} (${target.email})`;
  };

  const isTeamManager = selectedTeam?.managers?.includes(user?.userId);
  const isMainManager = selectedTeam?.mainManagerUserId === user?.userId;
  const canManageTeam = Boolean(isManager && isTeamManager);
  const canManageManagers = Boolean(isManager && isMainManager);

  const isInTeam = (userId) =>
    selectedTeam?.managers?.includes(userId) || selectedTeam?.members?.includes(userId);

  const availableUsers = selectedTeam
    ? users.filter((u) => !isInTeam(u.userId))
    : [];

  const searchedUsers = availableUsers.filter((u) => {
    const term = userSearchTerm.toLowerCase();
    const matchesTerm = u.username.toLowerCase().includes(term) || u.email.toLowerCase().includes(term);
    const matchesRole = userRoleFilter ? u.role === userRoleFilter : true;
    return matchesTerm && matchesRole;
  });

  const handleAddMemberAction = (targetId) => {
    if (!selectedTeam) return;
    const targetUser = userMap.get(targetId);
    if (!targetUser) return;
    if (isInTeam(targetId)) {
      pushToast("User already in team", "error");
      return;
    }
    handleAction(addMemberApi, selectedTeam.teamId, targetId, token);
  };

  const handleAddManagerAction = (targetId) => {
    if (!selectedTeam) return;
    const targetUser = userMap.get(targetId);
    if (!targetUser) return;
    if (targetUser.role !== "manager") {
      pushToast("User must have manager role", "error");
      return;
    }
    if (isInTeam(targetId)) {
      pushToast("User already in team", "error");
      return;
    }
    handleAction(addManagerApi, selectedTeam.teamId, targetId, token);
  };

  if (loading) {
    return (
      <section className="page-panel">
        <div className="card">
          Loading teams...
        </div>
      </section>
    );
  }

  return (
    <section className="page-panel">
      <div className="card teams-panel" style={{ width: '100%' }}>
        <h2>My Teams</h2>

        {isManager && (
          <form className="form-group" onSubmit={handleCreateTeam} style={{ display: 'flex', gap: '12px', marginBottom: '24px', alignItems: 'center' }}>
            <input
              type="text"
              placeholder="New Team Name"
              value={newTeamName}
              onChange={(e) => setNewTeamName(e.target.value)}
              style={{ flex: 1 }}
            />
            <button type="submit" className="primary" style={{ margin: 0, whiteSpace: 'nowrap' }}>Create Team</button>
          </form>
        )}

        {teams.length === 0 ? (
          <p className="muted">You are not in any teams yet.</p>
        ) : (
          <div className="table-wrap" style={{ marginBottom: '24px' }}>
            <table className="table">
              <thead>
                <tr>
                  <th style={{ width: '80px' }}>ID</th>
                  <th>Name</th>
                  <th style={{ width: '150px' }}>Action</th>
                </tr>
              </thead>
              <tbody>
                {teams.map((t) => (
                  <tr key={t.teamId}>
                    <td className="muted">#{t.teamId}</td>
                    <td><strong>{t.teamName}</strong></td>
                    <td>
                      <button
                        className="primary"
                        style={{
                          margin: 0,
                          padding: '0.6rem 1rem',
                          backgroundColor: selectedTeam?.teamId === t.teamId ? '#475569' : '',
                          color: selectedTeam?.teamId === t.teamId ? '#fff' : ''
                        }}
                        onClick={() => selectedTeam?.teamId === t.teamId ? setSelectedTeam(null) : handleSelectTeam(t.teamId)}
                      >
                        {selectedTeam?.teamId === t.teamId ? "Close Details" : "View Details"}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {selectedTeam && (
          <div className="card" style={{ marginTop: '24px', border: '1px solid rgba(148, 163, 184, 0.15)' }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
              <h3 style={{ margin: 0 }}>{selectedTeam.teamName} Details</h3>
              <button
                className="primary"
                style={{ margin: 0, backgroundColor: '#475569', color: '#fff' }}
                onClick={() => setSelectedTeam(null)}>
                Close
              </button>
            </div>
            <p>Main manager: {formatUserLabel(selectedTeam.mainManagerUserId)}</p>

            {isManager && (
              <div style={{ marginTop: '16px', padding: '16px', borderRadius: '16px', border: '1px solid var(--surface-border)', background: 'rgba(3, 7, 18, 0.35)' }}>
                <h4 style={{ marginTop: 0, marginBottom: '12px' }}>Team Members</h4>
                <button
                  className="primary"
                  style={{ margin: 0, backgroundColor: '#2dd4bf', color: '#030712' }}
                  onClick={() => {
                    setUserSearchTerm("");
                    setUserRoleFilter("");
                    setIsAddUserModalOpen(true);
                  }}
                  disabled={!canManageTeam || usersLoading}
                >
                  {usersLoading ? "Loading users..." : "+ Add Person to Team"}
                </button>
                {!usersLoading && availableUsers.length === 0 && (
                  <p className="muted" style={{ marginTop: '12px', marginBottom: 0 }}>All users are already in this team.</p>
                )}
              </div>
            )}

            <div style={{ display: 'grid', gap: '16px', marginTop: '16px' }}>
              <div>
                <h4 style={{ marginBottom: '8px' }}>Managers</h4>
                <div style={{ display: 'grid', gap: '8px' }}>
                  {(selectedTeam.managers || []).length === 0 && (
                    <p className="muted" style={{ margin: 0 }}>No managers yet.</p>
                  )}
                  {(selectedTeam.managers || []).map((managerId) => (
                    <div
                      key={`manager-${managerId}`}
                      style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0.6rem 0.9rem', borderRadius: '12px', border: '1px solid var(--surface-border)', background: 'rgba(15, 23, 42, 0.45)' }}
                    >
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span>{formatUserLabel(managerId)}</span>
                        {managerId === selectedTeam.mainManagerUserId && (
                          <span className="badge" style={{ background: 'var(--accent)', color: '#000', fontSize: '0.65rem' }}>Main Manager</span>
                        )}
                      </div>
                      {canManageManagers && (
                        <button
                          className="primary"
                          style={{ margin: 0, backgroundColor: '#475569', color: '#fff' }}
                          onClick={() => handleAction(removeManagerApi, selectedTeam.teamId, managerId, token)}
                          disabled={managerId === selectedTeam.mainManagerUserId}
                        >
                          Remove
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h4 style={{ marginBottom: '8px' }}>Members</h4>
                <div style={{ display: 'grid', gap: '8px' }}>
                  {(selectedTeam.members || []).length === 0 && (
                    <p className="muted" style={{ margin: 0 }}>No members yet.</p>
                  )}
                  {(selectedTeam.members || []).map((memberId) => (
                    <div
                      key={`member-${memberId}`}
                      style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0.6rem 0.9rem', borderRadius: '12px', border: '1px solid var(--surface-border)', background: 'rgba(15, 23, 42, 0.45)' }}
                    >
                      <span>{formatUserLabel(memberId)}</span>
                      {canManageTeam && (
                        <button
                          className="primary"
                          style={{ margin: 0, backgroundColor: '#475569', color: '#fff' }}
                          onClick={() => handleAction(removeMemberApi, selectedTeam.teamId, memberId, token)}
                        >
                          Remove
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* ADD USER MODAL */}
      {isAddUserModalOpen && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          backgroundColor: 'rgba(3, 7, 18, 0.8)', backdropFilter: 'blur(8px)',
          zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center',
          padding: '1.5rem'
        }}>
          <div className="card" style={{
            width: '100%', maxWidth: '900px', maxHeight: '90vh',
            display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: '0'
          }}>
            <div style={{ padding: '1.5rem 2rem', borderBottom: '1px solid var(--surface-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h2 style={{ margin: 0 }}>Add Person to Team</h2>
              <button
                onClick={() => setIsAddUserModalOpen(false)}
                style={{ background: 'transparent', border: 'none', color: 'var(--text-muted)', fontSize: '1.5rem', cursor: 'pointer' }}
              >
                ✕
              </button>
            </div>

            <div style={{ padding: '1.5rem 2rem', borderBottom: '1px solid var(--surface-border)', display: 'flex', gap: '1rem', background: 'rgba(15, 23, 42, 0.4)' }}>
              <input
                type="text"
                placeholder="Search username or email..."
                value={userSearchTerm}
                onChange={(e) => setUserSearchTerm(e.target.value)}
                style={{ flex: 1 }}
              />
              <select
                value={userRoleFilter}
                onChange={(e) => setUserRoleFilter(e.target.value)}
                style={{ width: '200px' }}
              >
                <option value="">All Roles</option>
                <option value="manager">Manager</option>
                <option value="member">Member</option>
              </select>
            </div>

            <div style={{ padding: '1.5rem 2rem', overflowY: 'auto', flex: 1 }}>
              {searchedUsers.length === 0 ? (
                <p className="muted text-center" style={{ padding: '2rem 0' }}>No users found matching your criteria.</p>
              ) : (
                <div className="table-wrap">
                  <table className="table">
                    <thead>
                      <tr>
                        <th style={{ width: '80px' }}>ID</th>
                        <th>User Info</th>
                        <th>Role</th>
                        <th style={{ textAlign: 'right' }}>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {searchedUsers.map((u) => (
                        <tr key={u.userId}>
                          <td className="muted" style={{ fontFamily: 'monospace' }}>#{u.userId}</td>
                          <td>
                            <div style={{ fontWeight: 600 }}>{u.username}</div>
                            <div className="muted" style={{ fontSize: '0.85rem' }}>{u.email}</div>
                          </td>
                          <td><span className={`badge badge-${u.role}`}>{u.role}</span></td>
                          <td style={{ textAlign: 'right' }}>
                            <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
                              {canManageTeam && (
                                <button
                                  className="primary"
                                  style={{ margin: 0, padding: '0.4rem 0.8rem', fontSize: '0.85rem' }}
                                  onClick={() => handleAddMemberAction(u.userId)}
                                >
                                  Add as Member
                                </button>
                              )}
                              {canManageManagers && u.role === 'manager' && (
                                <button
                                  className="primary"
                                  style={{ margin: 0, padding: '0.4rem 0.8rem', fontSize: '0.85rem', backgroundColor: '#0ea5e9' }}
                                  onClick={() => handleAddManagerAction(u.userId)}
                                >
                                  Add as Manager
                                </button>
                              )}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

@import url('https://fonts.googleapis.com/css2?family=Bricolage+Grotesque:opsz,wght@12..96,400..800&family=Plus+Jakarta+Sans:wght@400;500;600&display=swap');

:root {
  font-family: 'Plus Jakarta Sans', sans-serif;
  --bg-color: #030712;
  --surface-color: rgba(15, 23, 42, 0.45);
  --surface-border: rgba(148, 163, 184, 0.15);
  --surface-hover: rgba(30, 41, 59, 0.6);
  --text-main: #f8fafc;
  --text-muted: #94a3b8;
  --accent: #2dd4bf;
  --accent-glow: rgba(45, 212, 191, 0.35);
  --accent-alt: #38bdf8;
  --danger: #fb7185;
  --radius-card: 28px;
  --radius-pill: 999px;
  --transition: 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background-color: var(--bg-color);
  background-image:
    radial-gradient(circle at 15% 10%, rgba(45, 212, 191, 0.06), transparent 30%),
    radial-gradient(circle at 85% 80%, rgba(56, 189, 248, 0.06), transparent 30%),
    radial-gradient(circle at 50% 50%, rgba(3, 7, 18, 1), #030712 100%);
  background-attachment: fixed;
  color: var(--text-main);
  min-height: 100vh;
}

h1, h2, h3, h4, .nav-brand strong {
  font-family: 'Bricolage Grotesque', sans-serif;
  font-weight: 700;
}

a {
  color: var(--accent);
  text-decoration: none;
  transition: color var(--transition);
}

a:hover {
  color: var(--accent-alt);
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.app-shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  flex: 1;
  max-width: 1240px;
  margin: 0 auto;
  padding: 3rem 1.5rem;
  display: flex;
  flex-direction: column;
  width: 100%;
}

/* NAVBAR - Glassmorphism */
.navbar {
  background: rgba(3, 7, 18, 0.6);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--surface-border);
  padding: 1.2rem 1.5rem;
  position: sticky;
  top: 0;
  z-index: 100;
}

.nav-content {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.nav-brand {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.nav-brand strong {
  font-size: 1.6rem;
  letter-spacing: -0.5px;
  background: linear-gradient(90deg, #fff, #94a3b8);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.nav-brand span {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-family: 'Plus Jakarta Sans', sans-serif;
}

.nav-links {
  display: flex;
  gap: 0.8rem;
  align-items: center;
  flex-wrap: wrap;
}

.nav-link,
.nav-btn {
  color: var(--text-main);
  background: var(--surface-color);
  border: 1px solid var(--surface-border);
  padding: 0.6rem 1.2rem;
  border-radius: var(--radius-pill);
  cursor: pointer;
  font-size: 0.95rem;
  font-weight: 500;
  transition: all var(--transition);
}

.nav-link:hover,
.nav-btn:hover {
  background: var(--surface-hover);
  border-color: rgba(255, 255, 255, 0.3);
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.4);
}

.nav-link-active {
  background: rgba(45, 212, 191, 0.1);
  border-color: var(--accent);
  color: var(--accent);
  box-shadow: 0 0 15px var(--accent-glow);
}

/* CARDS & PANELS */
.card, .auth-hero {
  background: var(--surface-color);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--surface-border);
  border-radius: var(--radius-card);
  padding: 2.5rem;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  animation: fadeUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

.card h2 {
  margin-top: 0;
  margin-bottom: 1rem;
  font-size: 2.2rem;
  letter-spacing: -1px;
  color: #fff;
}

.page-panel {
  max-width: 1080px;
  margin: 0 auto;
}

.profile-panel {
  max-width: 800px;
}

.users-panel {
  min-height: 60vh;
}

/* AUTH LAYOUT */
.auth-layout {
  display: grid;
  grid-template-columns: minmax(360px, 1fr) minmax(460px, 1.2fr);
  gap: 1.5rem;
  max-width: 1100px;
  margin: auto;
  align-items: stretch;
  min-height: clamp(500px, 60vh, 700px);
}

.auth-hero {
  background: linear-gradient(135deg, rgba(15, 23, 42, 0.8) 0%, rgba(3, 7, 18, 0.9) 100%);
  display: flex;
  flex-direction: column;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.auth-hero::after {
  content: '';
  position: absolute;
  top: 0; right: 0; bottom: 0; left: 0;
  background: radial-gradient(circle at top right, var(--accent-glow), transparent 60%);
  pointer-events: none;
}

.auth-hero h2 {
  font-size: 3rem;
  z-index: 1;
}

.auth-hero p {
  color: var(--text-muted);
  font-size: 1.1rem;
  line-height: 1.6;
  z-index: 1;
}

.auth-kicker {
  color: var(--accent);
  text-transform: uppercase;
  font-size: 0.85rem;
  font-weight: 600;
  letter-spacing: 2px;
  margin-bottom: 1rem;
  z-index: 1;
}

/* FORMS */
.form-grid {
  display: grid;
  gap: 1rem;
}

input, select {
  width: 100%;
  padding: 1rem 1.2rem;
  border: 1px solid var(--surface-border);
  border-radius: 14px;
  background: rgba(3, 7, 18, 0.4);
  color: #fff;
  font: inherit;
  transition: var(--transition);
}

input::placeholder {
  color: rgba(148, 163, 184, 0.5);
}

input:focus, select:focus {
  outline: none;
  border-color: var(--accent);
  background: rgba(15, 23, 42, 0.8);
  box-shadow: 0 0 0 4px var(--accent-glow);
}

.input-error {
  border-color: var(--danger);
}

.field-error {
  color: var(--danger);
  font-size: 0.85rem;
  margin: -0.5rem 0 0 0.5rem;
}

button.primary {
  background: var(--text-main);
  color: #030712;
  border: none;
  padding: 1rem;
  border-radius: 14px;
  font-weight: 700;
  font-size: 1rem;
  cursor: pointer;
  transition: var(--transition);
  margin-top: 0.5rem;
  font-family: 'Plus Jakarta Sans', sans-serif;
}

button.primary:hover:not(:disabled) {
  background: var(--accent);
  transform: translateY(-2px);
  box-shadow: 0 10px 25px var(--accent-glow);
}

button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.muted {
  color: var(--text-muted);
}

.page-lead {
  font-size: 1.1rem;
  margin-bottom: 2rem;
}

.error {
  color: var(--danger);
  margin-top: 1rem;
  padding: 1rem;
  background: rgba(251, 113, 133, 0.1);
  border-radius: 12px;
  border: 1px solid rgba(251, 113, 133, 0.2);
}

/* DATA DISPLAYS */
.profile-grid {
  display: grid;
  gap: 0.8rem;
}

.profile-row {
  margin: 0;
  padding: 1.2rem;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--surface-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.profile-row strong {
  color: var(--text-muted);
}

.table-wrap {
  overflow-x: auto;
  border-radius: 20px;
  border: 1px solid var(--surface-border);
  background: rgba(3, 7, 18, 0.3);
}

.table {
  width: 100%;
  border-collapse: collapse;
}

.table th, .table td {
  padding: 1.2rem;
  text-align: left;
  border-bottom: 1px solid var(--surface-border);
}

.table th {
  background: rgba(255, 255, 255, 0.02);
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  font-size: 0.85rem;
  letter-spacing: 1px;
}

.table tr:hover td {
  background: rgba(255, 255, 255, 0.02);
}

.state-card {
  background: rgba(45, 212, 191, 0.1);
  border: 1px solid rgba(45, 212, 191, 0.2);
  color: var(--accent);
  padding: 1.5rem;
  border-radius: 16px;
  text-align: center;
  font-weight: 500;
}

/* BADGES & UTILS */
.badge {
  padding: 0.35rem 0.8rem;
  border-radius: var(--radius-pill);
  font-size: 0.75rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  display: inline-block;
}

.badge-manager {
  background: rgba(45, 212, 191, 0.15);
  color: var(--accent);
  border: 1px solid rgba(45, 212, 191, 0.3);
}

.badge-member {
  background: rgba(148, 163, 184, 0.1);
  color: var(--text-muted);
  border: 1px solid rgba(148, 163, 184, 0.2);
}

.text-accent { color: var(--accent); font-weight: 600; }
.text-danger { color: var(--danger); font-weight: 600; }

.spinner {
  width: 24px;
  height: 24px;
  border: 3px solid rgba(45, 212, 191, 0.3);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  display: inline-block;
  vertical-align: middle;
  margin-right: 0.5rem;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* TOASTS */
.toast-container {
  position: fixed;
  top: 1.5rem;
  right: 1.5rem;
  display: grid;
  gap: 0.8rem;
  width: min(400px, calc(100vw - 3rem));
  z-index: 1200;
}

.toast {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  border-radius: 16px;
  padding: 1rem 1.2rem;
  color: #fff;
  background: rgba(15, 23, 42, 0.9);
  backdrop-filter: blur(12px);
  border: 1px solid var(--surface-border);
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.6);
  border-left: 4px solid var(--accent-alt);
  animation: fadeUp 0.3s ease-out forwards;
}

.toast-success { border-left-color: var(--accent); }
.toast-error { border-left-color: var(--danger); }

.toast-close {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 1.5rem;
  padding: 0;
  line-height: 1;
}

@media (max-width: 960px) {
  .auth-layout {
    grid-template-columns: 1fr;
  }
  .card, .auth-hero {
    padding: 1.8rem;
  }
}

