package repository

import (
	"auth-user-management-service/internal/domain"

	"gorm.io/gorm"
)

// UserRepository defines the database operations for User
type UserRepository interface {
	CreateUser(user *domain.User) error
	FindByEmail(email string) (*domain.User, error)
	FindByID(id uint) (*domain.User, error)
	ListUsers(offset int, limit int) ([]domain.User, error)
	MarkUserVerified(id uint) error
}

type userRepositoryImpl struct {
	db *gorm.DB
}

// NewUserRepository creates a new user repository instance
func NewUserRepository(db *gorm.DB) UserRepository {
	return &userRepositoryImpl{db: db}
}

func (r *userRepositoryImpl) CreateUser(user *domain.User) error {
	return r.db.Create(user).Error
}

func (r *userRepositoryImpl) FindByEmail(email string) (*domain.User, error) {
	var user domain.User
	err := r.db.Where("email = ?", email).First(&user).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}

func (r *userRepositoryImpl) FindByID(id uint) (*domain.User, error) {
	var user domain.User
	err := r.db.First(&user, id).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}

func (r *userRepositoryImpl) ListUsers(offset int, limit int) ([]domain.User, error) {
	var users []domain.User
	err := r.db.Offset(offset).Limit(limit).Order("id ASC").Find(&users).Error
	if err != nil {
		return nil, err
	}
	return users, nil
}

func (r *userRepositoryImpl) MarkUserVerified(id uint) error {
	return r.db.Model(&domain.User{}).Where("id = ?", id).Updates(map[string]any{
		"is_verified": true,
	}).Error
}

package repository

import (
	"auth-user-management-service/internal/domain"

	"gorm.io/gorm"
)

// UserRepository defines the database operations for User
type UserRepository interface {
	CreateUser(user *domain.User) error
	FindByEmail(email string) (*domain.User, error)
	FindByID(id uint) (*domain.User, error)
	FindUsersByIDs(ids []uint) ([]domain.User, error)
	MarkUserVerified(id uint) error
	ListUsers(offset int, limit int) ([]domain.User, error)
}

type userRepositoryImpl struct {
	db *gorm.DB
}

// NewUserRepository creates a new user repository instance
func NewUserRepository(db *gorm.DB) UserRepository {
	return &userRepositoryImpl{db: db}
}

func (r *userRepositoryImpl) CreateUser(user *domain.User) error {
	return r.db.Create(user).Error
}

func (r *userRepositoryImpl) FindByEmail(email string) (*domain.User, error) {
	var user domain.User
	err := r.db.Where("email = ?", email).First(&user).Error
	return &user, err
}

func (r *userRepositoryImpl) FindByID(id uint) (*domain.User, error) {
	var user domain.User
	err := r.db.First(&user, id).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}

func (r *userRepositoryImpl) ListUsers(offset int, limit int) ([]domain.User, error) {
	var users []domain.User
	err := r.db.Offset(offset).Limit(limit).Order("id ASC").Find(&users).Error
	if err != nil {
		return nil, err
	}
	return users, nil
}

func (r *userRepositoryImpl) MarkUserVerified(id uint) error {
	return r.db.Model(&domain.User{}).Where("id = ?", id).Updates(map[string]any{
		"is_verified": true,
	}).Error
}

func (r *userRepositoryImpl) FindUsersByIDs(ids []uint) ([]domain.User, error) {
	var users []domain.User
	if len(ids) == 0 {
		return users, nil
	}
	err := r.db.Where("id IN ?", ids).Find(&users).Error
	return users, err
}

package usecase

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"auth-user-management-service/internal/domain"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/pkg/utils"

	"github.com/google/uuid"
	"gorm.io/gorm"
)

var (
	ErrEmailAlreadyUsed   = errors.New("email already in use")
	ErrInvalidCredentials = errors.New("invalid email or password")
	ErrUserNotFound       = errors.New("user not found")
	ErrSessionUnavailable = errors.New("session not found or already revoked")
	ErrJWTSecretMissing   = errors.New("jwt secret is not configured")
	ErrEmailNotVerified   = errors.New("email is not verified")
	ErrInvalidVerifyToken = errors.New("invalid verification token")
	ErrExpiredVerifyToken = errors.New("verification token expired")
	ErrSMTPNotConfigured  = errors.New("smtp is not fully configured")
)

// RegisterRequest defines the input payload for user registration.
// Public sign-up follows role model A: new users are always created as member.
type RegisterRequest struct {
	Password string `json:"password" binding:"required,min=6"`
	Password string `json:"password" binding:"required,min=8"`
	Role     string `json:"role" binding:"omitempty,oneof=manager member"`
}

// LoginRequest defines the input payload for user login.
type LoginRequest struct {
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required"`
}

// ResendVerificationRequest defines payload to resend verification emails.
type ResendVerificationRequest struct {
	Email string `json:"email" binding:"required,email"`
}

// UserResponse is a safe user payload without password.
type UserResponse struct {
	ID         uint      `json:"userId"`
	Username   string    `json:"username"`
	Email      string    `json:"email"`
	Role       string    `json:"role"`
	IsVerified bool      `json:"isVerified"`
	CreatedAt  time.Time `json:"createdAt"`
	UpdatedAt  time.Time `json:"updatedAt"`
}

// LoginResponse defines login output payload.
type LoginResponse struct {
	AccessToken string       `json:"accessToken"`
	ExpiresAt   time.Time    `json:"expiresAt"`
	User        UserResponse `json:"user"`
}

// AuthUsecase defines the business logic interface.
type AuthUsecase interface {
	Register(req *RegisterRequest) (*domain.User, error)
	VerifyEmail(rawToken string) error
	ResendVerification(req *ResendVerificationRequest) error
	Login(req *LoginRequest) (*LoginResponse, error)
	Logout(tokenID string) error
	ListUsers(page int, limit int) ([]UserResponse, error)
	GetMyProfile(userID uint) (*UserResponse, error)
}

type authUsecaseImpl struct {
	userRepo       repository.UserRepository
	sessionRepo    repository.SessionRepository
	verifyRepo     repository.EmailVerificationRepository
	jwtSecret      string
	jwtTokenTTL    time.Duration
	verifyTokenTTL time.Duration
	appBaseURL     string
	smtpConfig     utils.SMTPConfig
}

// NewAuthUsecase creates a new usecase instance (Dependency Injection).
func NewAuthUsecase(
	userRepo repository.UserRepository,
	sessionRepo repository.SessionRepository,
	verifyRepo repository.EmailVerificationRepository,
) AuthUsecase {
	ttl := 24 * time.Hour
	jwtExpiresHours := strings.TrimSpace(os.Getenv("JWT_EXPIRES_HOURS"))
	if jwtExpiresHours != "" {
		if parsed, err := time.ParseDuration(jwtExpiresHours + "h"); err == nil {
			ttl = parsed
		}
	}

	verifyTTLMinutes := readIntEnvWithDefault("EMAIL_VERIFY_TOKEN_TTL_MINUTES", 5)

	appBaseURL := strings.TrimSuffix(strings.TrimSpace(os.Getenv("APP_BASE_URL")), "/")
	if appBaseURL == "" {
		appBaseURL = "http://localhost:8080"
	}

	return &authUsecaseImpl{
		userRepo:       userRepo,
		sessionRepo:    sessionRepo,
		verifyRepo:     verifyRepo,
		jwtSecret:      strings.TrimSpace(os.Getenv("JWT_SECRET")),
		jwtTokenTTL:    ttl,
		verifyTokenTTL: time.Duration(verifyTTLMinutes) * time.Minute,
		appBaseURL:     appBaseURL,
		smtpConfig:     utils.LoadSMTPConfig(),
	}
}

// Register processes user registration and sends a verification link.
func (u *authUsecaseImpl) Register(req *RegisterRequest) (*domain.User, error) {
	existingUser, err := u.userRepo.FindByEmail(req.Email)
	if err == nil && existingUser != nil {
		return nil, ErrEmailAlreadyUsed
	}
	if err != nil && !errors.Is(err, gorm.ErrRecordNotFound) {
		return nil, err
	}

	hashedPassword, err := utils.HashPassword(req.Password)
	newUser := &domain.User{
		return nil, err
	}

	user := &domain.User{
		Username:   req.Username,
		Role:       "member",
		Password:   hashedPassword,
	if err := u.userRepo.CreateUser(newUser); err != nil {
		IsVerified: false,
	}

	if err := u.issueVerification(newUser); err != nil {
		return nil, err
	}

	return newUser, nil
		return nil, err
	}

	return user, nil
}

func (u *authUsecaseImpl) VerifyEmail(rawToken string) error {
	tokenHash := hashToken(rawToken)
	verificationToken, err := u.verifyRepo.FindByTokenHash(tokenHash)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return ErrInvalidVerifyToken
		}
		return err
	}

	if verificationToken.UsedAt != nil {
		return ErrInvalidVerifyToken
	}

	if time.Now().After(verificationToken.ExpiresAt) {
		return ErrExpiredVerifyToken
	}

	if err := u.userRepo.MarkUserVerified(verificationToken.UserID); err != nil {
		return err
	}
	if err := u.verifyRepo.MarkUsed(verificationToken.ID); err != nil {
		return err
	}

	return nil
}

func (u *authUsecaseImpl) ResendVerification(req *ResendVerificationRequest) error {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil
		}
		return err
	}

	if user.IsVerified {
		return nil
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	return u.issueVerification(user)
}

func (u *authUsecaseImpl) Login(req *LoginRequest) (*LoginResponse, error) {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrInvalidCredentials
		}
		return nil, err
	}

	if !utils.CheckPasswordHash(req.Password, user.Password) {
		return nil, ErrInvalidCredentials
	}

	if !user.IsVerified {
		return nil, ErrEmailNotVerified
	}

	if u.jwtSecret == "" {
		return nil, ErrJWTSecretMissing
	}

	tokenID := uuid.NewString()
	token, expiresAt, err := utils.GenerateToken(user.ID, user.Role, tokenID, u.jwtSecret, u.jwtTokenTTL)
	if err != nil {
		return nil, err
	}

	err = u.sessionRepo.CreateSession(&domain.Session{
		UserID:    user.ID,
		TokenID:   tokenID,
		ExpiresAt: expiresAt,
	})
	if err != nil {
		return nil, err
	}

	return &LoginResponse{
		AccessToken: token,
		ExpiresAt:   expiresAt,
		User:        toUserResponse(user),
	}, nil
}

func (u *authUsecaseImpl) Logout(tokenID string) error {
	err := u.sessionRepo.RevokeByTokenID(tokenID)
	if err != nil {
		return ErrSessionUnavailable
	}
	return nil
}

func (u *authUsecaseImpl) ListUsers(page int, limit int) ([]UserResponse, error) {
	if page < 1 {
		page = 1
	}
	if limit < 1 || limit > 100 {
		limit = 20
	}

	offset := (page - 1) * limit
	users, err := u.userRepo.ListUsers(offset, limit)
	if err != nil {
		return nil, err
	}

	response := make([]UserResponse, 0, len(users))
	for i := range users {
		response = append(response, toUserResponse(&users[i]))
	}

	return response, nil
}

func (u *authUsecaseImpl) GetMyProfile(userID uint) (*UserResponse, error) {
	user, err := u.userRepo.FindByID(userID)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrUserNotFound
		}
		return nil, err
	}

	response := toUserResponse(user)
	return &response, nil
}

func (u *authUsecaseImpl) issueVerification(user *domain.User) error {
	if !isSMTPConfigured(u.smtpConfig) {
		return ErrSMTPNotConfigured
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	if err := u.verifyRepo.DeleteActiveTokensByUserID(user.ID); err != nil {
		return err
	}

	rawToken := uuid.NewString()
	tokenHash := hashToken(rawToken)
	expiresAt := time.Now().Add(u.verifyTokenTTL)

	verificationToken := &domain.EmailVerificationToken{
		UserID:    user.ID,
		TokenHash: tokenHash,
		ExpiresAt: expiresAt,
	}

	if err := u.verifyRepo.CreateToken(verificationToken); err != nil {
		return err
	}

	verifyURL := fmt.Sprintf("%s/api/v1/auth/verify-email?token=%s", u.appBaseURL, rawToken)
	if err := utils.SendVerificationEmail(u.smtpConfig, user.Email, verifyURL); err != nil {
		return err
	}

	return nil
}

func toUserResponse(user *domain.User) UserResponse {
	return UserResponse{
		ID:         user.ID,
		Username:   user.Username,
		Email:      user.Email,
		Role:       user.Role,
		IsVerified: user.IsVerified,
		CreatedAt:  user.CreatedAt,
		UpdatedAt:  user.UpdatedAt,
	}
}

func hashToken(rawToken string) string {
	sum := sha256.Sum256([]byte(strings.TrimSpace(rawToken)))
	return hex.EncodeToString(sum[:])
}

func readIntEnvWithDefault(key string, fallback int) int {
	value := strings.TrimSpace(os.Getenv(key))
	if value == "" {
		return fallback
	}

	parsed, err := strconv.Atoi(value)
	if err != nil || parsed <= 0 {
		return fallback
	}
	return parsed
}

func isSMTPConfigured(cfg utils.SMTPConfig) bool {
	return cfg.Host != "" && cfg.Username != "" && cfg.Password != ""
}

package usecase

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"auth-user-management-service/internal/domain"
	"auth-user-management-service/internal/repository"
	"auth-user-management-service/pkg/utils"

	"github.com/google/uuid"
	"gorm.io/gorm"
)

var (
	ErrEmailAlreadyUsed   = errors.New("email already in use")
	ErrInvalidCredentials = errors.New("invalid email or password")
	ErrUserNotFound       = errors.New("user not found")
	ErrSessionUnavailable = errors.New("session not found or already revoked")
	ErrJWTSecretMissing   = errors.New("jwt secret is not configured")
	ErrEmailNotVerified   = errors.New("email is not verified")
	ErrInvalidVerifyToken = errors.New("invalid verification token")
	ErrExpiredVerifyToken = errors.New("verification token expired")
	ErrSMTPNotConfigured  = errors.New("smtp is not fully configured")
)

// RegisterRequest defines the input payload for user registration.
type RegisterRequest struct {
	Username string `json:"username" binding:"required"`
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required,min=8"`
	Role     string `json:"role" binding:"omitempty,oneof=manager member"`
}

// LoginRequest defines the input payload for user login.
type LoginRequest struct {
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password" binding:"required"`
}

// ResendVerificationRequest defines payload to resend verification emails.
type ResendVerificationRequest struct {
	Email string `json:"email" binding:"required,email"`
}

// UserResponse is a safe user payload without password.
type UserResponse struct {
	ID         uint      `json:"userId"`
	Username   string    `json:"username"`
	Email      string    `json:"email"`
	Role       string    `json:"role"`
	IsVerified bool      `json:"isVerified"`
	CreatedAt  time.Time `json:"createdAt"`
	UpdatedAt  time.Time `json:"updatedAt"`
}

// LoginResponse defines login output payload.
type LoginResponse struct {
	AccessToken string       `json:"accessToken"`
	ExpiresAt   time.Time    `json:"expiresAt"`
	User        UserResponse `json:"user"`
}

// AuthUsecase defines the business logic interface.
type AuthUsecase interface {
	Register(req *RegisterRequest) (*domain.User, error)
	VerifyEmail(rawToken string) error
	ResendVerification(req *ResendVerificationRequest) error
	Login(req *LoginRequest) (*LoginResponse, error)
	Logout(tokenID string) error
	ListUsers(page int, limit int) ([]UserResponse, error)
	GetMyProfile(userID uint) (*UserResponse, error)
	GetUsersByIDs(ids []uint) ([]UserResponse, error)
}

type authUsecaseImpl struct {
	userRepo       repository.UserRepository
	sessionRepo    repository.SessionRepository
	verifyRepo     repository.EmailVerificationRepository
	jwtSecret      string
	jwtTokenTTL    time.Duration
	verifyTokenTTL time.Duration
	appBaseURL     string
	smtpConfig     utils.SMTPConfig
}

// NewAuthUsecase creates a new usecase instance (Dependency Injection).
func NewAuthUsecase(
	userRepo repository.UserRepository,
	sessionRepo repository.SessionRepository,
	verifyRepo repository.EmailVerificationRepository,
) AuthUsecase {
	ttl := 24 * time.Hour
	jwtExpiresHours := strings.TrimSpace(os.Getenv("JWT_EXPIRES_HOURS"))
	if jwtExpiresHours != "" {
		if parsed, err := time.ParseDuration(jwtExpiresHours + "h"); err == nil {
			ttl = parsed
		}
	}

	verifyTTLMinutes := readIntEnvWithDefault("EMAIL_VERIFY_TOKEN_TTL_MINUTES", 5)

	appBaseURL := strings.TrimSuffix(strings.TrimSpace(os.Getenv("APP_BASE_URL")), "/")
	if appBaseURL == "" {
		appBaseURL = "http://localhost:8080"
	}

	return &authUsecaseImpl{
		userRepo:       userRepo,
		sessionRepo:    sessionRepo,
		verifyRepo:     verifyRepo,
		jwtSecret:      strings.TrimSpace(os.Getenv("JWT_SECRET")),
		jwtTokenTTL:    ttl,
		verifyTokenTTL: time.Duration(verifyTTLMinutes) * time.Minute,
		appBaseURL:     appBaseURL,
		smtpConfig:     utils.LoadSMTPConfig(),
	}
}

// Register processes user registration and sends a verification link.
func (u *authUsecaseImpl) Register(req *RegisterRequest) (*domain.User, error) {
	existingUser, err := u.userRepo.FindByEmail(req.Email)
	if err == nil && existingUser != nil {
		return nil, ErrEmailAlreadyUsed
	}
	if err != nil && !errors.Is(err, gorm.ErrRecordNotFound) {
		return nil, err
	}

	hashedPassword, err := utils.HashPassword(req.Password)
	if err != nil {
		return nil, err
	}

	user := &domain.User{
		Username:   req.Username,
		Email:      req.Email,
		Password:   hashedPassword,
		Role:       "member", // Force role to member upon registration
		IsVerified: false,
	}

	if err := u.userRepo.CreateUser(user); err != nil {
		return nil, err
	}

	if err := u.issueVerification(user); err != nil {
		return nil, err
	}

	return user, nil
}

func (u *authUsecaseImpl) VerifyEmail(rawToken string) error {
	tokenHash := hashToken(rawToken)
	verificationToken, err := u.verifyRepo.FindByTokenHash(tokenHash)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return ErrInvalidVerifyToken
		}
		return err
	}

	if verificationToken.UsedAt != nil {
		return ErrInvalidVerifyToken
	}

	if time.Now().After(verificationToken.ExpiresAt) {
		return ErrExpiredVerifyToken
	}

	if err := u.userRepo.MarkUserVerified(verificationToken.UserID); err != nil {
		return err
	}
	if err := u.verifyRepo.MarkUsed(verificationToken.ID); err != nil {
		return err
	}

	return nil
}

func (u *authUsecaseImpl) ResendVerification(req *ResendVerificationRequest) error {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil
		}
		return err
	}

	if user.IsVerified {
		return nil
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	return u.issueVerification(user)
}

func (u *authUsecaseImpl) Login(req *LoginRequest) (*LoginResponse, error) {
	user, err := u.userRepo.FindByEmail(req.Email)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrInvalidCredentials
		}
		return nil, err
	}

	if !utils.CheckPasswordHash(req.Password, user.Password) {
		return nil, ErrInvalidCredentials
	}

	if !user.IsVerified {
		return nil, ErrEmailNotVerified
	}

	if u.jwtSecret == "" {
		return nil, ErrJWTSecretMissing
	}

	tokenID := uuid.NewString()
	token, expiresAt, err := utils.GenerateToken(user.ID, user.Role, tokenID, u.jwtSecret, u.jwtTokenTTL)
	if err != nil {
		return nil, err
	}

	err = u.sessionRepo.CreateSession(&domain.Session{
		UserID:    user.ID,
		TokenID:   tokenID,
		ExpiresAt: expiresAt,
	})
	if err != nil {
		return nil, err
	}

	return &LoginResponse{
		AccessToken: token,
		ExpiresAt:   expiresAt,
		User:        toUserResponse(user),
	}, nil
}

func (u *authUsecaseImpl) Logout(tokenID string) error {
	err := u.sessionRepo.RevokeByTokenID(tokenID)
	if err != nil {
		return ErrSessionUnavailable
	}
	return nil
}

func (u *authUsecaseImpl) ListUsers(page int, limit int) ([]UserResponse, error) {
	if page < 1 {
		page = 1
	}
	if limit < 1 || limit > 100 {
		limit = 20
	}

	offset := (page - 1) * limit
	users, err := u.userRepo.ListUsers(offset, limit)
	if err != nil {
		return nil, err
	}

	response := make([]UserResponse, 0, len(users))
	for i := range users {
		response = append(response, toUserResponse(&users[i]))
	}

	return response, nil
}

func (u *authUsecaseImpl) GetMyProfile(userID uint) (*UserResponse, error) {
	user, err := u.userRepo.FindByID(userID)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrUserNotFound
		}
		return nil, err
	}

	response := toUserResponse(user)
	return &response, nil
}

func (u *authUsecaseImpl) GetUsersByIDs(ids []uint) ([]UserResponse, error) {
	users, err := u.userRepo.FindUsersByIDs(ids)
	if err != nil {
		return nil, err
	}

	response := make([]UserResponse, 0, len(users))
	for i := range users {
		response = append(response, toUserResponse(&users[i]))
	}

	return response, nil
}

func (u *authUsecaseImpl) issueVerification(user *domain.User) error {
	if !isSMTPConfigured(u.smtpConfig) {
		return ErrSMTPNotConfigured
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	if err := u.verifyRepo.DeleteActiveTokensByUserID(user.ID); err != nil {
		return err
	}

	rawToken := uuid.NewString()
	tokenHash := hashToken(rawToken)
	expiresAt := time.Now().Add(u.verifyTokenTTL)

	verificationToken := &domain.EmailVerificationToken{
		UserID:    user.ID,
		TokenHash: tokenHash,
		ExpiresAt: expiresAt,
	}

	if err := u.verifyRepo.CreateToken(verificationToken); err != nil {
		return err
	}

	verifyURL := fmt.Sprintf("%s/api/v1/auth/verify-email?token=%s", u.appBaseURL, rawToken)
	if err := utils.SendVerificationEmail(u.smtpConfig, user.Email, verifyURL); err != nil {
		return err
	}

	return nil
}

func toUserResponse(user *domain.User) UserResponse {
	return UserResponse{
		ID:         user.ID,
		Username:   user.Username,
		Email:      user.Email,
		Role:       user.Role,
		IsVerified: user.IsVerified,
		CreatedAt:  user.CreatedAt,
		UpdatedAt:  user.UpdatedAt,
	}
}

func hashToken(rawToken string) string {
	sum := sha256.Sum256([]byte(strings.TrimSpace(rawToken)))
	return hex.EncodeToString(sum[:])
}

func readIntEnvWithDefault(key string, fallback int) int {
	value := strings.TrimSpace(os.Getenv(key))
	if value == "" {
		return fallback
	}

	parsed, err := strconv.Atoi(value)
	if err != nil || parsed <= 0 {
		return fallback
	}
	return parsed
}

func isSMTPConfigured(cfg utils.SMTPConfig) bool {
	return cfg.Host != "" && cfg.Username != "" && cfg.Password != ""
}

package main

import (
	"log"
	"os"

	"team-management-service/config"
	"team-management-service/internal/handler"
	"team-management-service/internal/middleware"
	"team-management-service/internal/repository"
	"team-management-service/internal/usecase"

	"github.com/gin-gonic/gin"
)

func main() {
	config.LoadEnv()
	config.ConnectDB()

	teamRepo := repository.NewTeamRepository(config.DB)
	userRepo := repository.NewUserRepository(config.DB)
	teamUsecase := usecase.NewTeamUsecase(teamRepo, userRepo)
	teamHandler := handler.NewTeamHandler(teamUsecase)

	r := gin.Default()

	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"status":  "UP",
			"service": "team-management-service",
		})
	})

	api := r.Group("/api/v1")
	{
		protected := api.Group("/")
		protected.Use(middleware.AuthRequired())
		{
			teams := protected.Group("/teams")
			{
				teams.GET("/my", teamHandler.ListMyTeams)
				teams.GET("/:teamId", teamHandler.GetTeam)

				manager := teams.Group("")
				manager.Use(middleware.ManagerOnly())
				{
					manager.POST("", teamHandler.CreateTeam)
					manager.POST("/:teamId/members", teamHandler.AddMember)
					manager.DELETE("/:teamId/members/:userId", teamHandler.RemoveMember)
					manager.POST("/:teamId/managers", teamHandler.AddManager)
					manager.DELETE("/:teamId/managers/:userId", teamHandler.RemoveManager)
				}
			}
		}
	}

	port := os.Getenv("TEAM_SERVICE_PORT")
	if port == "" {
		port = "8081"
	}

	log.Printf("Team service is starting on port http://localhost:%s\n", port)
	if err := r.Run(":" + port); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

package config

import (
	"fmt"
	"log"
	"os"
	"path/filepath"

	"team-management-service/internal/domain"

	"github.com/joho/godotenv"
	"gorm.io/driver/postgres"
	"gorm.io/gorm"
)

var DB *gorm.DB

func LoadEnv() {
	envFile := os.Getenv("ENV_FILE")
	if envFile != "" {
		if err := godotenv.Load(envFile); err != nil {
			log.Printf("Failed to load env file from ENV_FILE (%s): %v", envFile, err)
		}
		return
	}

	candidates := []string{
		filepath.Join("..", "..", ".env.backend"),
		".env.backend",
	}

	for _, path := range candidates {
		if _, err := os.Stat(path); err == nil {
			if err := godotenv.Load(path); err != nil {
				log.Printf("Failed to load env file (%s): %v", path, err)
			}
			return
		}
	}

	log.Println("No .env.backend file found, using system environment variables")
}

func ConnectDB() {
	host := os.Getenv("DB_HOST")
	port := os.Getenv("DB_PORT")
	user := os.Getenv("DB_USER")
	password := os.Getenv("DB_PASSWORD")
	dbname := os.Getenv("DB_NAME")

	dsn := fmt.Sprintf("host=%s user=%s password=%s dbname=%s port=%s sslmode=disable TimeZone=Asia/Ho_Chi_Minh",
		host, user, password, dbname, port)

	db, err := gorm.Open(postgres.Open(dsn), &gorm.Config{})
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}

	fmt.Println("Connected to PostgreSQL successfully!")
	DB = db

	err = db.AutoMigrate(&domain.Team{}, &domain.TeamMembership{})
	if err != nil {
		log.Fatalf("Failed to auto migrate: %v", err)
	}
	fmt.Println("Auto migration completed!")
}

package domain

import (
	"time"

	"gorm.io/gorm"
)

// Team stores team ownership and metadata.
type Team struct {
	ID                uint           `gorm:"primaryKey;autoIncrement" json:"teamId"`
	TeamName          string         `gorm:"type:varchar(120);not null" json:"teamName"`
	MainManagerUserID uint           `gorm:"not null;index" json:"mainManagerUserId"`
	CreatedAt         time.Time      `json:"createdAt"`
	UpdatedAt         time.Time      `json:"updatedAt"`
	DeletedAt         gorm.DeletedAt `gorm:"index" json:"-"`
}

func (Team) TableName() string {
	return "teams"
}

package domain

import "time"

// TeamMembership maps users into teams with a team-scoped role.
type TeamMembership struct {
	ID             uint      `gorm:"primaryKey;autoIncrement" json:"id"`
	TeamID         uint      `gorm:"not null;index:idx_team_user,unique" json:"teamId"`
	UserID         uint      `gorm:"not null;index:idx_team_user,unique;index" json:"userId"`
	MembershipRole string    `gorm:"type:varchar(20);not null" json:"membershipRole"` // manager or member
	CreatedAt      time.Time `json:"createdAt"`
	UpdatedAt      time.Time `json:"updatedAt"`
}

func (TeamMembership) TableName() string {
	return "team_memberships"
}

package domain

// UserRef is a read-only mapping to auth service users table.
type UserRef struct {
	ID   uint   `gorm:"column:id;primaryKey"`
	Role string `gorm:"column:role"`
}

func (UserRef) TableName() string {
	return "users"
}

package handler

import (
	"errors"
	"net/http"
	"strconv"

	"team-management-service/internal/usecase"

	"github.com/gin-gonic/gin"
)

// TeamHandler binds HTTP requests to team usecases.
type TeamHandler struct {
	teamUsecase usecase.TeamUsecase
}

func NewTeamHandler(teamUsecase usecase.TeamUsecase) *TeamHandler {
	return &TeamHandler{teamUsecase: teamUsecase}
}

func (h *TeamHandler) CreateTeam(c *gin.Context) {
	userID, role, ok := getActorContext(c)
	if !ok {
		return
	}

	var req usecase.CreateTeamRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	team, err := h.teamUsecase.CreateTeam(userID, role, &req)
	if err != nil {
		h.handleUsecaseError(c, err)
		return
	}

	c.JSON(http.StatusCreated, team)
}

func (h *TeamHandler) ListMyTeams(c *gin.Context) {
	userID, _, ok := getActorContext(c)
	if !ok {
		return
	}

	teams, err := h.teamUsecase.ListMyTeams(userID)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to fetch teams"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"data": teams})
}

func (h *TeamHandler) GetTeam(c *gin.Context) {
	userID, _, ok := getActorContext(c)
	if !ok {
		return
	}

	teamID, parseErr := parseUintParam(c, "teamId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}

	team, err := h.teamUsecase.GetTeam(userID, teamID)
	if err != nil {
		h.handleUsecaseError(c, err)
		return
	}

	c.JSON(http.StatusOK, team)
}

func (h *TeamHandler) AddMember(c *gin.Context) {
	h.handleTeamAction(c, h.teamUsecase.AddMember, "Member added")
}

func (h *TeamHandler) RemoveMember(c *gin.Context) {
	userID, role, ok := getActorContext(c)
	if !ok {
		return
	}

	teamID, parseErr := parseUintParam(c, "teamId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}
	memberUserID, parseErr := parseUintParam(c, "userId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}

	if err := h.teamUsecase.RemoveMember(userID, role, teamID, memberUserID); err != nil {
		h.handleUsecaseError(c, err)
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Member removed"})
}

func (h *TeamHandler) AddManager(c *gin.Context) {
	h.handleTeamAction(c, h.teamUsecase.AddManager, "Manager added")
}

func (h *TeamHandler) RemoveManager(c *gin.Context) {
	userID, role, ok := getActorContext(c)
	if !ok {
		return
	}

	teamID, parseErr := parseUintParam(c, "teamId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}
	managerUserID, parseErr := parseUintParam(c, "userId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}

	if err := h.teamUsecase.RemoveManager(userID, role, teamID, managerUserID); err != nil {
		h.handleUsecaseError(c, err)
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Manager removed"})
}

func (h *TeamHandler) handleTeamAction(c *gin.Context, fn func(actorID uint, actorRole string, teamID uint, targetUserID uint) error, successMessage string) {
	userID, role, ok := getActorContext(c)
	if !ok {
		return
	}

	teamID, parseErr := parseUintParam(c, "teamId")
	if parseErr != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": parseErr.Error()})
		return
	}

	var req usecase.TeamActionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := fn(userID, role, teamID, req.UserID); err != nil {
		h.handleUsecaseError(c, err)
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": successMessage})
}

func (h *TeamHandler) handleUsecaseError(c *gin.Context, err error) {
	switch {
	case errors.Is(err, usecase.ErrTeamNameRequired):
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrTeamNotFound):
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrUserNotFound):
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrAlreadyInTeam):
		c.JSON(http.StatusConflict, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrNotTeamMember):
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrMainManagerRequired), errors.Is(err, usecase.ErrForbidden), errors.Is(err, usecase.ErrNotTeamManager):
		c.JSON(http.StatusForbidden, gin.H{"error": err.Error()})
	case errors.Is(err, usecase.ErrGlobalManagerRequired), errors.Is(err, usecase.ErrUseManagerEndpoint), errors.Is(err, usecase.ErrCannotRemoveMain):
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	default:
		c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
	}
}

func parseUintParam(c *gin.Context, key string) (uint, error) {
	raw := c.Param(key)
	parsed, err := strconv.ParseUint(raw, 10, 64)
	if err != nil {
		return 0, errors.New("invalid path parameter")
	}
	return uint(parsed), nil
}

func getActorContext(c *gin.Context) (uint, string, bool) {
	userIDValue, exists := c.Get("userID")
	if !exists {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "missing user context"})
		return 0, "", false
	}

	userID, ok := userIDValue.(uint)
	if !ok {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid user context"})
		return 0, "", false
	}

	roleValue, exists := c.Get("role")
	if !exists {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "missing role context"})
		return 0, "", false
	}

	role, ok := roleValue.(string)
	if !ok || role == "" {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid role context"})
		return 0, "", false
	}

	return userID, role, true
}

package middleware

import (
	"net/http"
	"os"
	"strings"

	"team-management-service/pkg/utils"

	"github.com/gin-gonic/gin"
)

// AuthRequired validates JWT and sets user context.
func AuthRequired() gin.HandlerFunc {
	return func(c *gin.Context) {
		authorizationHeader := c.GetHeader("Authorization")
		if authorizationHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing Authorization header"})
			c.Abort()
			return
		}

		parts := strings.SplitN(authorizationHeader, " ", 2)
		if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid Authorization header format"})
			c.Abort()
			return
		}

		jwtSecret := strings.TrimSpace(os.Getenv("JWT_SECRET"))
		claims, err := utils.ParseToken(parts[1], jwtSecret)
		if err != nil {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid or expired token"})
			c.Abort()
			return
		}

		c.Set("userID", claims.UserID)
		c.Set("role", claims.Role)
		c.Next()
	}
}

// ManagerOnly restricts access to manager users.
func ManagerOnly() gin.HandlerFunc {
	return func(c *gin.Context) {
		role, exists := c.Get("role")
		if !exists || role != "manager" {
			c.JSON(http.StatusForbidden, gin.H{"error": "manager role required"})
			c.Abort()
			return
		}
		c.Next()
	}
}

package repository

import (
	"errors"

	"team-management-service/internal/domain"

	"gorm.io/gorm"
)

// TeamRepository defines persistence operations for teams and memberships.
type TeamRepository interface {
	CreateTeamWithMainManager(team *domain.Team) error
	FindTeamByID(teamID uint) (*domain.Team, error)
	ListTeamsByUser(userID uint) ([]domain.Team, error)
	ListMembershipsByTeam(teamID uint) ([]domain.TeamMembership, error)
	FindMembership(teamID uint, userID uint) (*domain.TeamMembership, error)
	CreateMembership(teamID uint, userID uint, role string) error
	UpdateMembershipRole(teamID uint, userID uint, role string) error
	DeleteMembership(teamID uint, userID uint) error
}

type teamRepositoryImpl struct {
	db *gorm.DB
}

func NewTeamRepository(db *gorm.DB) TeamRepository {
	return &teamRepositoryImpl{db: db}
}

func (r *teamRepositoryImpl) CreateTeamWithMainManager(team *domain.Team) error {
	return r.db.Transaction(func(tx *gorm.DB) error {
		if err := tx.Create(team).Error; err != nil {
			return err
		}

		membership := domain.TeamMembership{
			TeamID:         team.ID,
			UserID:         team.MainManagerUserID,
			MembershipRole: "manager",
		}
		return tx.Create(&membership).Error
	})
}

func (r *teamRepositoryImpl) FindTeamByID(teamID uint) (*domain.Team, error) {
	var team domain.Team
	err := r.db.First(&team, teamID).Error
	if err != nil {
		return nil, err
	}
	return &team, nil
}

func (r *teamRepositoryImpl) ListTeamsByUser(userID uint) ([]domain.Team, error) {
	var teams []domain.Team
	err := r.db.Table("teams").
		Joins("JOIN team_memberships ON team_memberships.team_id = teams.id").
		Where("team_memberships.user_id = ?", userID).
		Order("teams.id ASC").
		Find(&teams).Error
	if err != nil {
		return nil, err
	}
	return teams, nil
}

func (r *teamRepositoryImpl) ListMembershipsByTeam(teamID uint) ([]domain.TeamMembership, error) {
	var memberships []domain.TeamMembership
	err := r.db.Where("team_id = ?", teamID).Order("user_id ASC").Find(&memberships).Error
	if err != nil {
		return nil, err
	}
	return memberships, nil
}

func (r *teamRepositoryImpl) FindMembership(teamID uint, userID uint) (*domain.TeamMembership, error) {
	var membership domain.TeamMembership
	err := r.db.Where("team_id = ? AND user_id = ?", teamID, userID).First(&membership).Error
	if err != nil {
		return nil, err
	}
	return &membership, nil
}

func (r *teamRepositoryImpl) CreateMembership(teamID uint, userID uint, role string) error {
	membership := domain.TeamMembership{
		TeamID:         teamID,
		UserID:         userID,
		MembershipRole: role,
	}
	return r.db.Create(&membership).Error
}

func (r *teamRepositoryImpl) UpdateMembershipRole(teamID uint, userID uint, role string) error {
	result := r.db.Model(&domain.TeamMembership{}).
		Where("team_id = ? AND user_id = ?", teamID, userID).
		Update("membership_role", role)
	if result.Error != nil {
		return result.Error
	}
	if result.RowsAffected == 0 {
		return gorm.ErrRecordNotFound
	}
	return nil
}

func (r *teamRepositoryImpl) DeleteMembership(teamID uint, userID uint) error {
	result := r.db.Where("team_id = ? AND user_id = ?", teamID, userID).
		Delete(&domain.TeamMembership{})
	if result.Error != nil {
		return result.Error
	}
	if result.RowsAffected == 0 {
		return errors.New("membership not found")
	}
	return nil
}

package repository

import (
	"team-management-service/internal/domain"

	"gorm.io/gorm"
